+fn parse_props_fields(payload: &str) -> Option<Vec<String>> {
+    for line in payload.lines() {
+        if let Some(rest) = line.strip_prefix("props:") {
+            let mut values: Vec<String> = rest
+                .split(',')
+                .map(str::trim)
+                .filter(|field| !field.is_empty())
+                .map(ToString::to_string)
+                .collect();
+            values.sort();
+            values.dedup();
+            return Some(values);
+        }
+    }
+    None
+}
