+fn minimize_conformance_case(
+    source: &str,
+    expected: &str,
+    actual: &str,
+    failure_class: ConformanceFailureClass,
+) -> ConformanceMinimizationOutcome {
+    let source_segments = split_source_segments(source);
+    let expected_lines = split_output_lines(expected);
